// تحليل مسار البيع الكامل
const inputData = items[0].json;
const { step, userId, data, timestamp } = inputData;

// تحديد مرحلة البيع
const sellSteps = {
  'seller_type': {
    stepNumber: 2,
    completion: 20,
    nextStep: 'vehicle_data',
    criticalData: ['sellerType', 'businessInfo']
  },
  'vehicle_data': {
    stepNumber: 3,
    completion: 40,
    nextStep: 'equipment',
    criticalData: ['make', 'model', 'year', 'mileage']
  },
  'equipment': {
    stepNumber: 4,
    completion: 60,
    nextStep: 'images',
    criticalData: ['safety', 'comfort', 'tech']
  },
  'images': {
    stepNumber: 5,
    completion: 75,
    nextStep: 'price',
    criticalData: ['imageCount', 'mainImage']
  },
  'price': {
    stepNumber: 6,
    completion: 90,
    nextStep: 'contact',
    criticalData: ['price', 'currency', 'negotiable']
  },
  'contact': {
    stepNumber: 7,
    completion: 95,
    nextStep: 'publish',
    criticalData: ['name', 'phone', 'location']
  },
  'published': {
    stepNumber: 8,
    completion: 100,
    nextStep: 'complete',
    criticalData: ['listingId', 'publicUrl']
  }
};

// الحصول على معلومات الخطوة
const stepInfo = sellSteps[step] || {
  stepNumber: 1,
  completion: 10,
  nextStep: 'unknown',
  criticalData: []
};

// تحليل جودة البيانات
const dataQuality = {
  complete: stepInfo.criticalData.every(field => data && data[field]),
  missing: stepInfo.criticalData.filter(field => !data || !data[field]),
  score: data ? (Object.keys(data).length / stepInfo.criticalData.length) * 100 : 0
};

// اكتشاف نقاط التوقف المحتملة
const dropOffRisk = {
  high: stepInfo.completion > 80 && dataQuality.score < 70,
  medium: stepInfo.completion > 50 && dataQuality.score < 50,
  low: dataQuality.score > 80
};

// تحديد التدخلات المطلوبة
let interventions = [];
if (dropOffRisk.high) {
  interventions.push('Send urgent assistance offer');
  interventions.push('Activate customer support chat');
}
if (dataQuality.missing.length > 0) {
  interventions.push(`Help with: ${dataQuality.missing.join(', ')}`);
}
if (stepInfo.completion > 70) {
  interventions.push('Send completion encouragement');
}

// تحليل التوقيت
const timeAnalysis = {
  currentTime: new Date(timestamp),
  hour: new Date(timestamp).getHours(),
  isBusinessHours: new Date(timestamp).getHours() >= 9 && new Date(timestamp).getHours() <= 17,
  isWeekend: [0, 6].includes(new Date(timestamp).getDay())
};

// اقتراحات تحسين التحويل
let conversionTips = [];
if (!timeAnalysis.isBusinessHours) {
  conversionTips.push('Consider follow-up during business hours');
}
if (stepInfo.completion > 50 && stepInfo.completion < 100) {
  conversionTips.push('High-intent user - prioritize for support');
}

return [{
  json: {
    userId,
    step,
    stepInfo,
    dataQuality,
    dropOffRisk,
    interventions,
    timeAnalysis,
    conversionTips,
    processedAt: new Date().toISOString(),
    needsAttention: dropOffRisk.high || dataQuality.score < 50
  }
}];
